-- ====================================================================
-- SETUP COMPLETO Plataforma Interna LATAM ConsultUs + MaximUs
-- ====================================================================
-- Idempotente: podes correrlo varias veces sin romper nada.
-- Crea todas las columnas y tablas que faltan + carga los activos
-- por cliente desde el Excel de Mayo 2026.
-- Correr en Supabase Dashboard -> SQL Editor -> New query -> paste -> Run
-- ====================================================================

-- 1) Columnas que faltaban
alter table public.team              add column if not exists non_assignable boolean not null default false;

alter table public.consultora_cards  add column if not exists a_cargo text default '';
alter table public.consultora_cards  add column if not exists comentarios text default '';

alter table public.maximus_clients   add column if not exists asignado_a text references public.team(id);
alter table public.maximus_clients   add column if not exists nota_plan text;
alter table public.maximus_clients   add column if not exists fecha_renovacion text;
alter table public.maximus_clients   add column if not exists telefono text;
alter table public.maximus_clients   add column if not exists activos jsonb default '[]'::jsonb;

alter table public.maximus_prospects add column if not exists pais text;
alter table public.maximus_prospects add column if not exists asignado_a text references public.team(id);
alter table public.maximus_prospects add column if not exists jira_key text;
alter table public.maximus_prospects add column if not exists jira_estado text;
alter table public.maximus_prospects add column if not exists nota_plan text;

-- 2) Tablas nuevas
create table if not exists public.analisis (
  id           text primary key,
  ticker       text not null,
  titulo       text not null,
  pdf_url      text not null,
  nota         text default '',
  uploaded_by  text references public.team(id),
  uploaded_at  timestamptz not null default now()
);
create index if not exists idx_analisis_ticker on public.analisis(ticker);
create index if not exists idx_analisis_uploaded_at on public.analisis(uploaded_at desc);

create table if not exists public.envios_whatsapp (
  id            text primary key,
  analisis_id   text references public.analisis(id) on delete cascade,
  cliente_id    text references public.maximus_clients(id),
  contacto      text,
  telefono      text,
  mensaje       text,
  enviado_by    text references public.team(id),
  enviado_at    timestamptz not null default now()
);
create index if not exists idx_envios_analisis on public.envios_whatsapp(analisis_id);

-- 3) RLS + Realtime
alter table public.analisis         enable row level security;
alter table public.envios_whatsapp  enable row level security;

do $X$
declare t text;
begin
  for t in select unnest(array['analisis','envios_whatsapp']) loop
    execute format('drop policy if exists "open_select" on public.%I', t);
    execute format('drop policy if exists "open_insert" on public.%I', t);
    execute format('drop policy if exists "open_update" on public.%I', t);
    execute format('drop policy if exists "open_delete" on public.%I', t);
    execute format('create policy "open_select" on public.%I for select using (true)', t);
    execute format('create policy "open_insert" on public.%I for insert with check (true)', t);
    execute format('create policy "open_update" on public.%I for update using (true) with check (true)', t);
    execute format('create policy "open_delete" on public.%I for delete using (true)', t);
  end loop;
end $X$;

do $Y$
begin
  begin alter publication supabase_realtime add table public.analisis;        exception when duplicate_object then null; end;
  begin alter publication supabase_realtime add table public.envios_whatsapp; exception when duplicate_object then null; end;
end $Y$;

